const Q_BIOLOGY_2004=[{"id": "objective>Biology>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The endoplasmic reticulum is represented by the part labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The endoplasmic reticulum is represented by the part labeled IV. It is a network of membranous tubules within the cytoplasm of a eukaryotic cell, continuous with the nuclear membrane. It usually has ribosomes attached and is involved in protein and lipid synthesis.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled II is responsible for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protein synthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excretion</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labeled II is mitochondria and is responsible for respiration.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rods in the retina of the eye are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cells </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tissues </div>", "<div style=\"font-family:Cambria;font-size:17px;\">organs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">systems</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rods are a type of photoreceptor cells in the retina of the eye that detect motion, provide peripheral vision, and function well in low light. These are not tissues, organs or systems, but individual cells that make up part of the complex system of vision.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The absence of special food and water conducting systems restricts the body size in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">algae, liverworts and mosses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liverworts, mosses and ferns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the bryophytes ad the pteridophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the thallophytes and the pteridophytes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Algae, liverworts, and mosses are all simple plants that lack the specialized vascular systems (xylem and phloem) found in more complex plants. These systems are responsible for conducting water, minerals, and food throughout the plant, allowing it to grow larger. Without these systems, these simple plants are restricted in size.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A plant-like feature in Euglena is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pellicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pigment spot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large vacuole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gullet</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The plant-like feature in Euglena is the pigment spot because it contains chloroplasts for photosynthesis, a characteristic feature of plants. The pigment spot helps the Euglena to detect light, thus directing it towards light for photosynthesis.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PROTISTA"}, {"id": "objective>Biology>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common characteristic of the fungal hyphae is the possession of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cell-like compartments with one nucleus each</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell walls that are both rigid and chitinous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a multicellular mycelium in the substrate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cell-like partitions formed by cross-walls</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common characteristic of the fungal hyphae is the possession of cell walls that are both rigid and chitinous. Fungal hyphae are characterized by their rigid cell walls, which are made up of chitin, a strong but flexible nitrogen-containing polysaccharide.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : FUNGI"}, {"id": "objective>Biology>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insects are considered the most successful among the invertebrates because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">possess exoskeletons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">survive in various environmental conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have wings for flight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">possess the ability to change their forms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insects are considered the most successful among the invertebrates because they survive in various environmental conditions. Insects are highly adaptable and can survive in a wide range of environments, from deserts to polar regions. This adaptability is a key factor in their success as a group.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The larval stage of a mosquito is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wriggler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grub</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maggot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caterpillar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The larval stage of a mosquito is called a wriggler. This is because of the wriggling motion they make when they swim. The other options, grub, maggot, and caterpillar, are larval stages of other insects, not mosquitoes.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the long-winged reproductive in a termite colony is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disperse the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feed the young</div>", "<div style=\"font-family:Cambria;font-size:17px;\">participate in swarming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect the young</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the long-winged reproductive in a termite colony is to disperse the population. These termites are also known as alates or swarmers, and their primary role is to leave their current colony, mate, and establish new colonies, thereby dispersing the termite population. The other options are not the primary functions of the long-winged reproductive termites.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A peculiar characteristic of mammals is that they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have teeth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are warm-blooded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have sebaceous glands</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A peculiar characteristic of mammals is that they possess the sebaceous gland. It is a small gland in the skin which secretes a lubricating oily matter (sebum) into the hair follicles to lubricate the skin and hair.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the internal structure of plants, a wide pith in the center is common to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dicot stems and monocot stems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dicot stems and monocot roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dicot roots and monocot roots</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dicot roots and monocot stems</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pith is the central part of the stem and roots. In dicot stems and monocot roots, a wide pith is common.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gall bladder of a mammal has a duct connected to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duodenum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small intestine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pancreas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gall bladder is a small sac-like organ located by the liver in the human body. It is connected to the liver via a duct called the cystic duct, which joins with the common hepatic duct to form the common bile duct. The bile produced by the liver is stored and concentrated in the gall bladder before it is released into the duodenum.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All living cells require water because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a medium for all metabolic reactions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a medium that neutralizes acids in cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is the main source of energy for the cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevents the development of diseases in cell</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water is essential to all living cells because it serves as a medium for all metabolic reactions. Metabolic reactions are the chemical processes that occur within a living organism in order to maintain life, and these reactions need a medium in which to occur, which is provided by water. Water is not the main source of energy for cells, it does not neutralize acids in cells, and it does not prevent the development of diseases in cells.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The breakdown of fats and oils into simpler absorbable compounds is catalyzed by the group of enzymes called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lipases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amylases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peptidases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lipases are a group of enzymes that help in the breakdown of fats and oils into simpler absorbable compounds. They catalyze the hydrolysis of triglycerides (fats and oils) into glycerol and free fatty acids, which are simpler and can be absorbed by the body.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Yam is used in this set-up because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is permeable to the salt solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is a plant material</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acts as a storage organ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acts as a semi-permeable membrane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yam is used in the set up because it allows partial movement of fluid i.e it is semi-permeable.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following results is to be expected if the set-up is left for several hours?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Decrease in the size of the yam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Movement of the salt solution into the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease in the volume of water inside the yam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Movement of water from the salt solution into the yam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the set-up is left for several hours there will be decrease in the volume of water inside the yam for osmosis to occur. This because the cell is in a stronger solution hence it is an hypertonic solution. </div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The surface of an alveolus in a mammal is well supplied with tiny blood vessels known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">arterioles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">venules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arteries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capillaries</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The surface of an alveolus in a mammal is well supplied with tiny blood vessels known as capillaries. Capillaries are the smallest blood vessels in the body and they facilitate the exchange of oxygen, carbon dioxide, and other waste products between the blood and the tissues.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The anaerobic fermentation of a glucose molecule yields</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">38 ATP molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 ATP molecules and alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyruvic acid and alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water and carbon(IV)oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The anaerobic fermentation of a glucose molecule yields 2 ATP molecules and alcohol. This process, also known as alcoholic fermentation, occurs in yeast and some types of bacteria. It begins with the breakdown of one molecule of glucose and ends with the production of two molecules of ethanol (alcohol) and two molecules of ATP, which is used as a source of energy.</div>", "topic": "RESPIRATION : ANAEROBIC RESPIRATION"}, {"id": "objective>Biology>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The opening of the stoma is controlled by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presence of a pore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in solute concentration in the guard cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of guard cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in solute concentration in the guard cells</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The opening and closing of stomata are controlled by the turgidity of guard cells. When the solute concentration in the guard cells increases, water enters the cells by osmosis, making them turgid and causing the stomata to open. Conversely, when the solute concentration decreases, water leaves the cells, making them flaccid and causing the stomata to close.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The sweat gland is the structure labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV. In a skin structure diagram, the sweat gland appears as a coiled tubular structure located in the dermis. It consists of a coiled secretory portion and a straight or wavy duct that extends to the skin surface, where it opens as a sweat pore.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the part labelled III is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contract to pull the hair erect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct nervous impulses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carry blood and nitrogenous waste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce oil for the skin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the part labelled III is to contract to pull the hair erect.</div>", "topic": "INTERNAL STRUCTURE OF A MAMMAL : MAMMALIAN INTERNAL ORGANS"}, {"id": "objective>Biology>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The bones labelled II are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cervical vertebrae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sacral vertebrae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thoracic vertebrae</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbar vertebrae</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">lumbar vertebrae is found after the thoracic vertebra(upper abdomen)</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of joint between adjacent bones in the part labelled II is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ball and socket joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sliding joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hinge joint</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suture joint</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of joints present between the adjacent bones in the lumbar vertebrae is the ball and socket joint. Gliding joints, or plane joints, are synovial joints with flat or slightly curved surfaces that allow bones to slide past each other in various directions. These joints enable limited but versatile movement. Examples include the intercarpal joints in the wrist, intertarsal joints in the ankle, facet joints in the spine, and the sternoclavicular joint. They provide stability and flexibility to the skeleton.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of reproduction that is common to both Hydra and Yeast is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conjugation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">binary fusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grafting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">budding</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both Hydra and Yeast reproduce asexually through a process called budding. In this process, a new organism develops from an outgrowth or bud due to cell division at one particular site. The new organism remains attached as it grows, separating from the parent organism only when it is mature.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled II is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">style </div>", "<div style=\"font-family:Cambria;font-size:17px;\">filament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stigma </div>", "<div style=\"font-family:Cambria;font-size:17px;\">anther</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Anther is part of the male reproductive organ of a flower , it has a swollen head and is attached to the filament </div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows.  <br/>  <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The process of pollination involves the transfer of pollens from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I to II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II to III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III to IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV to I.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of pollination involves the transfer of pollen grains from the anther(ii) to the stigma(iii).</div>", "topic": "REPRODUCTION : SEXUAL REPRODUCTION"}, {"id": "objective>Biology>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The eggs of birds contain relatively larger quantities of yolk than those of amphibians and reptiles because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">birds are generally bigger in size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embryonic development is longer in birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">those of birds are fertilized internally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds lay shelled eggs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bird eggs contain more yolk than those of amphibians and reptiles because embryonic development is longer in birds. The yolk provides the necessary nutrients for the developing embryo.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Epigeal germination of a seed is characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more rapid elongation of the hypocotyl than the epicotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more rapid elongation of the epicotyl than the hypocotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal growth rate of both the hypocotyl and epicotyl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of growth of the hypocotyl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Epigeal germination is characterized by the rapid elongation of the hypocotyl, which lifts the cotyledons above the ground. The hypocotyl is the part of the stem of an embryo plant beneath the stalks of the seed leaves (cotyledons) and directly above the root. The epicotyl is the region of an embryo or seedling stem above the cotyledon. In epigeal germination, the hypocotyl elongates rapidly and forms a hook, pulling the cotyledons and the shoot tip above the ground.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a nursing mother is not producing enough milk, her hormonal system is probably in deficient in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prolactin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">testosterone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thyroxin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">insulin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prolactin is a hormone produced by the pituitary gland in the brain that plays a vital role in the production of milk in mammals. If a nursing mother is not producing enough milk, it could be due to a deficiency in prolactin. Testosterone, thyroxin, and insulin do not directly influence milk production.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two key cations involved in the action potential of nervous transmissions are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The action potential in nerve transmission involves the movement of sodium ions (Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) and potassium ions (K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>). During an action potential, Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> ions rush into the neuron, causing depolarization. Repolarization occurs when K+ ions rush out of the neuron. This sequence of events allows for the transmission of electrical signals along the neuron. Iron (Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) and magnesium (Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) are not directly involved in the action potential of nervous transmissions.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A caterpillar and an aphid living in different parts of the same plant can be said to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">occupy the same ecological niche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be in different habitats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occupy different ecological niches</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be in similar microhabitats</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ecological niche refers to the role an organism plays in its environment, including its interactions with other organisms and its environment. A caterpillar and an aphid, although living on the same plant, occupy different ecological niches because they interact differently with their environment and other organisms.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table below to answer the question that follows.  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Ecological Zone</td><td style=\"border:1px solid black;text-align:center;\"> Temperature(°C)</td><td style=\"border:1px solid black;text-align:center;\"> Rainfall(mm) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">I</td><td style=\"border:1px solid black;text-align:center;\">45</td><td style=\"border:1px solid black;text-align:center;\">300 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">II</td><td style=\"border:1px solid black;text-align:center;\">32</td><td style=\"border:1px solid black;text-align:center;\">2000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">III</td><td style=\"border:1px solid black;text-align:center;\">30</td><td style=\"border:1px solid black;text-align:center;\">2200 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">IV</td><td style=\"border:1px solid black;text-align:center;\">15</td><td style=\"border:1px solid black;text-align:center;\">800</td></tr></table></div> <br/>  <br/> High relative humidity will be expected in Zones</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. Areas with high temperatures and high rainfall are likely to have high relative humidity because the high temperature allows the air to hold more moisture, and the high rainfall provides the moisture. Therefore, Zones II and III, which have high temperatures and high rainfall, are likely to have high relative humidity.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table below to answer the question that follows.  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Ecological Zone</td><td style=\"border:1px solid black;text-align:center;\"> Temperature(°C)</td><td style=\"border:1px solid black;text-align:center;\"> Rainfall(mm) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">I</td><td style=\"border:1px solid black;text-align:center;\">45</td><td style=\"border:1px solid black;text-align:center;\">300 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">II</td><td style=\"border:1px solid black;text-align:center;\">32</td><td style=\"border:1px solid black;text-align:center;\">2000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">III</td><td style=\"border:1px solid black;text-align:center;\">30</td><td style=\"border:1px solid black;text-align:center;\">2200 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">IV</td><td style=\"border:1px solid black;text-align:center;\">15</td><td style=\"border:1px solid black;text-align:center;\">800</td></tr></table></div> <br/> Which of the zones is likely to be a desert?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A desert is characterized by low rainfall and high temperatures. From the table, Zone I has the highest temperature (45°C) and the lowest rainfall (300mm), which are characteristics of a desert. Therefore, Zone I is likely to be a desert.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The association between termites and the cellulose-digesting protozoans in their guts is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Saprophytism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutualism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parasitism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commensalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relationship between termites and the cellulose-digesting protozoans in their guts is an example of mutualism. Mutualism is a type of symbiotic relationship where both organisms benefit. In this case, the termites benefit by being able to digest cellulose, which they wouldn't be able to do on their own, and the protozoans benefit by having a safe environment to live in and a constant food supply.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The progressive loss of energy at each level in a food chain leads to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in biomass at each successive level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in biomass at each successive level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the number of organisms at each successive level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the total weight of living matter at each successive level</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The progressive loss of energy at each level in a food chain leads to a decrease in biomass at each successive level. This is because energy is lost at each trophic level in the form of heat due to metabolic processes. As a result, less energy is available to support biomass at the next trophic level. This concept is known as the '10% rule' in ecology, which states that, on average, only about 10% of the total energy at one trophic level is available to the next.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One adaptation of reptiles to water loss is the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">keratinous scales</div>", "<div style=\"font-family:Cambria;font-size:17px;\">claws on limbs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long tails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long sticky tongues</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One adaptation of reptiles to water loss is the presence of keratinous scales. These scales are made of keratin, a protein that is also found in human hair and nails. The scales form a barrier that helps to prevent water loss from the reptile's body, allowing them to live in dry environments. This is a form of structural adaptation, where an organism's physical features evolve over time to help it survive in its environment.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A state in Nigeria that is most susceptible to desert encroachment is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kwara </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taraba </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kastina</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kastina is a state in Nigeria that is most susceptible to desert encroachment. This is due to its geographical location in the northern part of Nigeria which is closer to the Sahara desert. The process of desert encroachment, also known as desertification, is the transformation of arable or habitable land into desert, due to climate change or destructive land use.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : DESERT"}, {"id": "objective>Biology>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scarcity of food causes a sudden decrease in population size by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreasing the reproductive rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bringing about immigration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raising the mortality rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minimizing the rate of competition</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scarcity of food can cause a sudden decrease in population size by raising the mortality rate. When there is a scarcity of food, organisms struggle to get the necessary nutrients for survival. This can lead to malnutrition, disease, and ultimately death, thereby increasing the mortality rate.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The soil type that will be most difficult to plough in a wet season is one that is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loamy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">clayey </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silty</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clayey soil will be the most difficult to plough in a wet season. This is because clayey soil has small, tightly packed particles that stick together when wet, making it heavy and sticky. This makes it difficult to work with, especially when ploughing.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A farmer practice that results in the loss of soil fertility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush fallowing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shifting cultivation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous cropping</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Continuous cropping is a farming practice that results in the loss of soil fertility. This is because the same crop is grown on the same land year after year without giving the soil time to replenish its nutrients. The other options like mixed farming, bush fallowing, and shifting cultivation are all practices that help maintain or improve soil fertility.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Paternity disputes can most accurately be resolved through the use of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fingerprinting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blood group typing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">DNA analysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tongue-rolling</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paternity disputes can most accurately be resolved through the use of DNA analysis. DNA analysis involves comparing the DNA of the child with the alleged father to determine if there is a match. This is the most accurate method because each person's DNA is unique to them, except for identical twins. The other options like fingerprinting, blood group typing, and tongue-rolling are not as accurate for determining paternity.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a Mendelian cross of red and white varieties of the four o'clock plant, F1 <br/> generation expresses incomplete dominance by having flowers which are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white </div>", "<div style=\"font-family:Cambria;font-size:17px;\">red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pink </div>", "<div style=\"font-family:Cambria;font-size:17px;\">multicoloured</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a Mendelian cross of red and white varieties of the four o'clock plant, F1 generation expresses incomplete dominance by having flowers which are pink. Incomplete dominance is a form of intermediate inheritance in which one allele for a specific trait is not completely expressed over its paired allele. This results in a third phenotype in which the expressed physical trait is a combination of the phenotypes of both alleles. In this case, the red and white colors blend to produce pink.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Identical twins inherit their genes from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different eggs and sperms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same egg and sperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two eggs and a sperm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one egg and two sperms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Identical twins are formed from a single fertilized egg, which splits in two. Therefore, they inherit their genes from the same egg and sperm.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sex-linked genes are located on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y – chromosome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X – and Y – chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homologous chromosomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X – chromosome</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sex-linked genes are located on both X and Y chromosomes. These are the chromosomes that determine the sex of an individual. Genes that are carried by either sex chromosome are said to be sex linked.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of intraspecific competition?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a Lizard and an ant-eater chasing an insect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a worker termite and a soldier in a limited space</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a hawk and an eagle targeting the same chicken</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yam and potato shoots growing out through the same window</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intraspecific competition refers to competition between members of the same species for resources. A worker termite and a soldier in a limited space is an example of this, as they are both termites competing for the same space.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants survive hot dry conditions by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">storing water in large parenchyma cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producing numerous leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">having numerous stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">having evergreen leaves</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plants survive hot dry conditions by storing water in large parenchyma cells. Parenchyma cells are a type of plant tissue that can store water, nutrients, and other substances. In hot and dry conditions, these cells can store water to help the plant survive periods of drought.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rodents gnaw on food with their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">molar teeth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strong jaws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flat-ridged teeth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chisel-like front teeth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rodents gnaw on food with their chisel-like front teeth. These teeth, known as incisors, are sharp and strong, allowing rodents to gnaw through a variety of materials. The incisors of rodents never stop growing, which is why they constantly gnaw on things to keep their teeth from becoming too long.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The spot and stripes of the leopard and tiger are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cryptic colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warning colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disruptive colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">counter shading</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The spot and stripes of the leopard and tiger are examples of disruptive colouration. Disruptive coloration (also known as disruptive camouflage or disruptive patterning) is a form of camouflage that works by breaking up the outlines of an animal.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An evidence of the relationship between living organisms and their extinct relatives can best be obtained from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">embryology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative anatomy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">comparative physiology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paleontology</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The best evidence of the relationship between living organisms and their extinct relatives can be obtained from paleontology. Paleontology is the scientific study of the history of life on Earth through the examination of plant and animal fossils. This includes the study of body fossils, tracks, burrows, cast-off parts, fossilised feces, palynomorphs and chemical residues. Because humans have encountered fossils for millennia, paleontology has a long history both before and after becoming formalized as a science. This history of paleontology traces aspects of that chronicle.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic exhibited by all living organisms is  <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sexual reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aerobic respiration <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ability to move from one place to another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the ability to remove unwanted substances </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The characteristic exhibited by all living organisms is the ability to remove unwanted substances. This is a process known as excretion. Excretion is a process by which metabolic waste is eliminated from an organism. In vertebrates this is primarily carried out by the lungs, kidneys and skin. This is in contrast with secretion, where the substance may have specific tasks after leaving the cell. Excretion is an essential process in all forms of life.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}];
